const SUPABASE_URL = 'https://faklxfakgzkpkbxfihzh.supabase.co';
const SUPABASE_API_KEY = 'sb_publishable_HsIkelEZaIr0VauiB3GgIQ_59XJRoWc';
const trigger = $('workflow_trigger').first().json;

let recipient_email = trigger.recipient_email;
let bcc_email = trigger.bcc_email;
let story_structure_guidelines = '';
try {
  const rows = await this.helpers.httpRequest({
    method: 'GET',
    url: `${SUPABASE_URL}/rest/v1/app_config_v2?key=in.(recipient_email,bcc_email,story_structure_guidelines)&select=key,value`,
    headers: { 'apikey': SUPABASE_API_KEY, 'Authorization': `Bearer ${SUPABASE_API_KEY}` }
  });
  for (const row of rows) {
    if (row.key === 'recipient_email' && !recipient_email) recipient_email = row.value;
    if (row.key === 'bcc_email' && !bcc_email) bcc_email = row.value;
    if (row.key === 'story_structure_guidelines') story_structure_guidelines = row.value;
  }
} catch (e) {
  if (!recipient_email) recipient_email = 'eric@agileadtesting.com';
}

// Auto-load outline from writing_projects when project_title is provided
let project_outline = null;
const project_title = trigger.project_title || '';
if (project_title) {
  try {
    const resp = await this.helpers.httpRequest({
      method: 'GET',
      url: `${SUPABASE_URL}/rest/v1/writing_projects_v2?title=ilike.${encodeURIComponent(project_title)}&limit=1`,
      headers: { 'apikey': SUPABASE_API_KEY, 'Authorization': `Bearer ${SUPABASE_API_KEY}` }
    });
    const projects = Array.isArray(resp) ? resp : [resp];
    if (projects.length > 0 && projects[0]?.outline) {
      project_outline = projects[0].outline;
    }
  } catch (e) {}
}

return [{ json: { SUPABASE_URL, SUPABASE_API_KEY, recipient_email, bcc_email: bcc_email || '', story_structure_guidelines, project_outline, project_title } }];

const supabaseUrl = $('settings').first().json.SUPABASE_URL;
const apiKey = $('settings').first().json.SUPABASE_API_KEY;
const headers = { 'apikey': apiKey, 'Authorization': 'Bearer ' + apiKey };

let files = [];
try {
  const listResp = await this.helpers.httpRequest({
    method: 'POST',
    url: supabaseUrl + '/storage/v1/object/list/author-content',
    headers: { ...headers, 'Content-Type': 'application/json' },
    body: { prefix: 'writing-samples', limit: 20 },
    returnFullResponse: false
  });
  files = (listResp || []).filter(f => f.name && f.name !== '.gitkeep' && f.metadata?.size > 0);
} catch (e) {
  return [{ json: { samples_text: 'No writing samples available.', sample_count: 0 } }];
}

if (files.length === 0) {
  return [{ json: { samples_text: 'No writing samples available.', sample_count: 0 } }];
}

const samples = [];
for (const file of files.slice(0, 5)) {
  try {
    const content = await this.helpers.httpRequest({
      method: 'GET',
      url: supabaseUrl + '/storage/v1/object/author-content/writing-samples/' + file.name,
      headers: headers,
      returnFullResponse: false,
      encoding: 'utf-8',
      json: false
    });
    samples.push('--- ' + file.name + ' ---\n' + (typeof content === 'string' ? content : JSON.stringify(content)));
  } catch (e) {}
}

const samplesText = samples.length > 0 ? samples.join('\n\n') : 'No writing samples available.';
return [{ json: { samples_text: samplesText, sample_count: samples.length } }];

