const research = $('research_topic').first().json.message || '';
let style = '';
try { style = $('style_analysis').first().json.output || $('style_analysis').first().json.text || ''; } catch (e) { style = ''; }
const trigger = $('workflow_trigger').first().json;
const genre = $('get_genre_config').first().json;
const genreData = Array.isArray(genre) ? genre[0] : genre;
const genreName = genreData?.genre_name || 'Science Fiction';
const genreGuidelines = genreData?.writing_guidelines || '';
const structureGuidelines = $('settings').first().json.story_structure_guidelines || '';
const length = parseInt(trigger.length) || 3000;

// Auto-load outline from writing_projects if available
const outline = $('settings').first().json.project_outline;
const projectTitle = $('settings').first().json.project_title;

// Determine title: outline title > project_title > first words of premise
let title = 'Untitled';
if (outline && typeof outline === 'object' && outline.title) {
  title = outline.title;
} else if (projectTitle) {
  title = projectTitle;
} else if (trigger.premise) {
  title = trigger.premise.split(' ').slice(0, 5).join(' ');
}

// Build outline section for the prompt if a stored outline exists
let outlineSection = '';
let premiseText = trigger.premise || '';
if (outline && typeof outline === 'object') {
  // Use the stored premise — it's the canonical version from brainstorming
  if (outline.premise) premiseText = outline.premise;
  const parts = [];
  if (outline.premise) parts.push('PREMISE: ' + outline.premise);
  if (outline.themes) parts.push('THEMES: ' + (Array.isArray(outline.themes) ? outline.themes.join(', ') : outline.themes));
  if (outline.characters) {
    parts.push('CHARACTERS:\n' + outline.characters.map(c => 
      '- ' + c.name + ' (' + c.role + '): ' + c.arc + (c.description ? ' \u2014 ' + c.description : '')
    ).join('\n'));
  }
  if (outline.chapters) {
    parts.push('STORY STRUCTURE:\n' + outline.chapters.map(ch => 
      'Part ' + ch.number + ' \u2014 ' + ch.title + ': ' + ch.brief + (ch.arc_notes ? ' [Arc: ' + ch.arc_notes + ']' : '')
    ).join('\n'));
  }
  outlineSection = parts.join('\n\n');
} else if (typeof outline === 'string' && outline) {
  outlineSection = outline;
}

const outlineBlock = outlineSection ? `\n\n## Story Outline (FOLLOW THIS EXACTLY — do not rename characters, change the premise, or deviate from this outline)\n${outlineSection}` : '';

const prompt = `You are a world-class science fiction author.\n\n## Genre\n${genreName}\n\n## Genre Guidelines\n${genreGuidelines}\n\n## Writing Prime Directive\nWrite like a human, not a machine. Use clear, everyday language and short sentences. Cut cliches \u2014 no \"revolutionize,\" \"game-changing,\" \"unleash,\" or \"delve.\" Get to the point \u2014 remove filler words. No hype, just facts. Be genuine \u2014 don't fake excitement. Show, don't tell \u2014 use concrete details and sensory moments instead of vague claims. Stay focused \u2014 one idea per paragraph. Keep paragraphs short. Respect the reader's intelligence. Write like you'd tell a story to a smart friend. Skip unnecessary adjectives and adverbs. Relax about perfect grammar if it makes dialogue or narration sound more natural. After drafting, cut anything that doesn't move the story forward.\n\n## Story Structure Guidelines\n${structureGuidelines}${outlineBlock}\n\n## Research\n${research}\n\n## Writing Style\n${style}\n\n## Assignment\nWrite a complete short story titled \"${title}\" of approximately ${length} words.\n\n- Premise: ${premiseText}\n- Tone: ${trigger.tone}\n- Target length: ${length} words${outlineSection ? '\n- IMPORTANT: Follow the outline above exactly. Use the character names, premise, and story structure as specified. Do not rename characters or change the story concept.' : ''}\n\n## Structure\nWrite the story with natural scene breaks (use --- between scenes). Include:\n1. Opening: Establish the world, introduce the protagonist\n2. Rising action: Develop conflict, deepen character\n3. Climax and resolution\n\nWrite the story text directly. No JSON wrapping, no metadata, no scene labels. Just the story.`;

return [{ json: { prompt: prompt, title: title } }];

const storyText = $input.first().json.output || $input.first().json.text || '';
const title = $('build_story_prompt').first().json.title || 'Untitled';
const trigger = $('workflow_trigger').first().json;
const genre = $('get_genre_config').first().json;
const genreData = Array.isArray(genre) ? genre[0] : genre;
const genreName = genreData?.genre_name || 'Science Fiction';

// Extract the opening scene (first ~300 words) for visual reference
const openingScene = storyText.split(/\n---\n|\n\n/)[0]?.substring(0, 1200) || storyText.substring(0, 1200);

// Build a rich visual image description from the story content
const imagePrompt = `A cinematic, atmospheric cover image for a ${genreName} short story titled "${title}".

Story premise: ${trigger.premise}
Tone: ${trigger.tone || 'literary'}

Key scene from the opening:
${openingScene}

Create a single powerful visual scene that captures the mood, setting, and central tension of this story. Focus on the most visually striking moment — the environment, lighting, character silhouettes, and atmospheric details. Do NOT include any text, titles, or words in the image.`;

return [{ json: { story_text: storyText, title: title, image_prompt: imagePrompt } }];

const supabaseUrl = $('settings').first().json.SUPABASE_URL;
const apiKey = $('settings').first().json.SUPABASE_API_KEY;
const headers = { 'apikey': apiKey, 'Authorization': 'Bearer ' + apiKey, 'Content-Type': 'application/json' };

try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: supabaseUrl + '/rest/v1/published_content_v2',
    headers,
    body: {
      title: $('set_full_story').first().json.title,
      content_type: 'short_story',
      genre_slug: $('workflow_trigger').first().json.genre_slug,
      content_text: $('set_full_story').first().json.story_text,
      storage_path: $json.Key || '',
      project_id: null,
      chapter_number: null,
      status: 'draft'
    }
  });
} catch (e) {
  // Don't fail the workflow if draft insert fails
}

return $input.all();
